{"path": "/tmp/sv-10af6d97511f42ec940da6f2bdae4132/Components/Pages/Catalog/CatalogToolbar.razor", "file_text": "<div class="catalog-toolbar">
    <div class="sort-control">
        <label for="sortSelect">Sort by:</label>
        <select id="sortSelect" value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="result-summary">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            @($"Showing {start}–{end} of {TotalCount} products")
        }
        else
        {
            @("No products found")
        }
    </span>
</div>

@code {
