{"path": "/tmp/sv-10af6d97511f42ec940da6f2bdae4132/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="page-btn" disabled="@(Page <= 1)" @onclick="() => GoToPage(Page - 1)">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNumber = i;
        <button class="page-btn @(pageNumber == Page ? "active" : "")"
                @onclick="() => GoToPage(pageNumber)">
            @pageNumber
        </button>
    }

    <button class="page-btn" disabled="@(Page >= TotalPages)" @onclick="() => GoToPage(Page + 1)">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

