.catalog-filters {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    padding: 1.25rem;
    background: #fafafa;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
}

.catalog-filters h2 {
    margin: 0 0 0.25rem;
    font-size: 1.2rem;
}

fieldset {
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.75rem;
    margin: 0;
}

legend {
    font-weight: 600;
    font-size: 0.9rem;
    padding: 0 0.25rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    padding: 0.15rem 0;
}

.price-inputs {
    display: flex;
    gap: 0.75rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.85rem;
    flex: 1;
}

