    padding: 0.35rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    background: #3b82f6;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
}

.btn-apply:hover {
    background: #2563eb;
}

.btn-clear {
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    background: #fff;
    color: #555;
    font-weight: 600;
    cursor: pointer;
}

.btn-clear:hover {
    background: #f5f5f5;
}

