arguments.file_text:
@page "/catalog"
@using sv_10af6d97511f42ec940da6f2bdae4132.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_loading)
{
    <div class="catalog-status">
        <p>Loading products…</p>
    </div>
}
else if (_error is not null)
{
    <div class="catalog-status catalog-error">
        <p>Something went wrong: @_error</p>
        <button @onclick="LoadDataAsync">Try Again</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <aside class="catalog-sidebar">
            <CatalogFilters Categories="_categories"
                            CurrentFilter="_filter"
                            OnApplyFilters="HandleApplyFilters"
                            OnClearFilters="HandleClearFilters" />
        </aside>

        <main class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_page"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_products.Count == 0)
            {
                <div class="catalog-status">
                    <p>No products match your filters.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="HandleAddToCart" />
            }

            @if (_totalPages > 1)
            {
                <CatalogPagination Page="_page"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            var result = await productsTask;

            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await SearchAsync();
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
    align-items: flex-start;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-status {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #c0392b;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: 1px solid #c0392b;
    border-radius: 4px;
    background: #fff;
    color: #c0392b;
    cursor: pointer;
    font-weight: 600;
}

.catalog-error button:hover {
    background: #fdf0ef;
}

