.catalog-layout {
    display: flex;
    gap: 1.5rem;
    align-items: flex-start;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-status {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #c0392b;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: 1px solid #c0392b;
    border-radius: 4px;
    background: #fff;
    color: #c0392b;
    cursor: pointer;
    font-weight: 600;
}

.catalog-error button:hover {
    background: #fdf0ef;
}

